import{_ as t,o,c as a,ae as r}from"./chunks/framework.DTQlDYOH.js";const h=JSON.parse('{"title":"Reference: Value resolution and references","description":"","frontmatter":{},"headers":[],"relativePath":"reference/values-and-refs.md","filePath":"reference/values-and-refs.md"}'),n={name:"reference/values-and-refs.md"};function s(i,e,l,c,g,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="reference-value-resolution-and-references" tabindex="-1">Reference: Value resolution and references <a class="header-anchor" href="#reference-value-resolution-and-references" aria-label="Permalink to &quot;Reference: Value resolution and references&quot;">​</a></h1><p>Many fields in B.A.G.E.L. (move arguments, end results, conditions) accept <strong>resolved values</strong>: special objects that the engine replaces with a value from the game state or context. Use these in <strong>matcher</strong> properties, <strong>result</strong> values, <strong>expression</strong> arguments, and similar places.</p><h2 id="ctxpath" tabindex="-1">ctxPath <a class="header-anchor" href="#ctxpath" aria-label="Permalink to &quot;ctxPath&quot;">​</a></h2><p>Path into <strong>ctx</strong> (boardgame.io context).</p><ul><li><strong>type</strong>: <code>&quot;ctxPath&quot;</code></li><li><strong>path</strong>: Array of keys, e.g. <code>[&quot;currentPlayer&quot;]</code>, <code>[&quot;playOrder&quot;]</code>.</li></ul><p>Example: type <code>&quot;ctxPath&quot;</code>, path <code>[&quot;currentPlayer&quot;]</code> for the current player ID.</p><h2 id="contextpath" tabindex="-1">contextPath <a class="header-anchor" href="#contextpath" aria-label="Permalink to &quot;contextPath&quot;">​</a></h2><p>Path into the <strong>current evaluation context</strong> (e.g. move validation, end check, ForEach loop).</p><ul><li><strong>type</strong>: <code>&quot;contextPath&quot;</code></li><li><strong>path</strong>: Array of keys/indexes into the context object.</li></ul><p>Common context keys: <strong>moveArguments</strong> (arguments for the current move), <strong>originalTarget</strong> (the space/entity the player chose), <strong>loopTarget</strong> (current item in a ForEach), <strong>target</strong>, <strong>results</strong> (from condition evaluation, e.g. HasLine matches).</p><p>Example: winner from a HasLine result — path into <code>results[0].matches[0][0].entities[0].attributes.player</code>, or use shorthand <strong>ownerOfFirstResultEntity</strong>.</p><h2 id="gamepath" tabindex="-1">gamePath <a class="header-anchor" href="#gamepath" aria-label="Permalink to &quot;gamePath&quot;">​</a></h2><p>Path into the game state <strong>G</strong> (e.g. bank, _meta).</p><ul><li><strong>type</strong>: <code>&quot;gamePath&quot;</code></li><li><strong>path</strong>: Array, e.g. <code>[&quot;_meta&quot;, &quot;previousPayloads&quot;, &quot;jumpChecker&quot;, &quot;arguments&quot;, &quot;entity&quot;]</code>, <code>[&quot;_meta&quot;, &quot;passedPlayers&quot;, &quot;length&quot;]</code>.</li></ul><p>Used in: Checkers (same piece must keep jumping; pass count for win).</p><h2 id="expression" tabindex="-1">expression <a class="header-anchor" href="#expression" aria-label="Permalink to &quot;expression&quot;">​</a></h2><p>Evaluate a formula with <a href="https://github.com/silentmatt/expr-eval" target="_blank" rel="noreferrer">expr-eval</a>.</p><ul><li><strong>type</strong>: <code>&quot;expression&quot;</code></li><li><strong>expression</strong>: String (e.g. <code>&quot;player == &#39;0&#39; ? -1 : 1&quot;</code>, <code>&quot;(currentPlayer + 1) % 2&quot;</code>).</li><li><strong>arguments</strong>: Object mapping variable names to resolved values (which can use <strong>ctxPath</strong>, <strong>contextPath</strong>, <strong>gamePath</strong>, etc.).</li></ul><p>Used in: Checkers (player-relative coordinates; winner when opponent passed).</p><h2 id="relativecoordinates" tabindex="-1">relativeCoordinates <a class="header-anchor" href="#relativecoordinates" aria-label="Permalink to &quot;relativeCoordinates&quot;">​</a></h2><p>Resolve to the space at a relative offset from a given space (e.g. “one step up-right”).</p><ul><li><strong>type</strong>: <code>&quot;relativeCoordinates&quot;</code></li><li><strong>target</strong> — Optional. Defaults to <strong>originalTarget</strong> in context. Resolves to a space.</li><li><strong>location</strong> — [dx, dy] or a resolved value (e.g. <strong>expression</strong> that returns different offsets per player).</li></ul><p>Used in: Checkers (move/jump directions), Connect Four (space below for “gravity”).</p><h2 id="coordinates" tabindex="-1">Coordinates <a class="header-anchor" href="#coordinates" aria-label="Permalink to &quot;Coordinates&quot;">​</a></h2><p>Absolute coordinates of a space in its parent grid.</p><ul><li><strong>type</strong>: <code>&quot;Coordinates&quot;</code></li><li><strong>target</strong> — Optional. Defaults to <strong>originalTarget</strong>. Resolves to a space; parent must be a Grid.</li></ul><p>Used in: Checkers (king row: e.g. <code>destinationCoordinates[1] == 0</code> for player 0).</p><h2 id="relativepath" tabindex="-1">RelativePath <a class="header-anchor" href="#relativepath" aria-label="Permalink to &quot;RelativePath&quot;">​</a></h2><p>Path into <strong>target.attributes</strong> (rule + state of an entity).</p><ul><li><strong>type</strong>: <code>&quot;RelativePath&quot;</code></li><li><strong>target</strong> — Resolved to an entity.</li><li><strong>path</strong> — Array of keys into that entity’s attributes.</li></ul><h2 id="parent" tabindex="-1">Parent <a class="header-anchor" href="#parent" aria-label="Permalink to &quot;Parent&quot;">​</a></h2><p>The parent container of a space or entity (e.g. the grid that contains the space).</p><ul><li><strong>type</strong>: <code>&quot;Parent&quot;</code></li><li><strong>target</strong> — Optional. Defaults to <strong>originalTarget</strong>.</li></ul><h2 id="map" tabindex="-1">map <a class="header-anchor" href="#map" aria-label="Permalink to &quot;map&quot;">​</a></h2><p>Map a set of targets to another value (e.g. “for each space, get this attribute”).</p><ul><li><strong>type</strong>: <code>&quot;map&quot;</code></li><li><strong>targets</strong> — Condition or resolution that yields multiple targets.</li><li><strong>mapping</strong> — Resolved for each target (with <strong>loopTarget</strong> in context). Result is the array of mapped values.</li></ul><p><strong>mapMax</strong> — Same as <strong>map</strong> but returns only the targets whose mapped value is maximum (e.g. “players with highest score”).</p><h2 id="pick" tabindex="-1">Pick <a class="header-anchor" href="#pick" aria-label="Permalink to &quot;Pick&quot;">​</a></h2><p>Subset of attributes from a resolved entity.</p><ul><li><strong>type</strong>: <code>&quot;Pick&quot;</code></li><li><strong>target</strong> — Resolved to an entity.</li><li><strong>properties</strong> — Array of attribute names.</li></ul><hr><p>When documenting or writing game JSON, remember: <strong>ctxPath</strong> = boardgame.io context; <strong>contextPath</strong> = current B.A.G.E.L. evaluation context (move, end check, loop); <strong>gamePath</strong> = game state G.</p>',42)])])}const d=t(n,[["render",s]]);export{h as __pageData,d as default};
